const item = $input.first().json;
const deliveryTarget = item.delivery_target || { target_type: item.target_type || "channel", target_id: item.target_id || item.default_channel_id || "" };
const title = item.title || item.delivery_title || item.account_name || item.workflow_name || "Workflow Update";
const body = item.body || item.delivery_body || item.summary || item.message || "";
return [{ json: { ...item, delivery_payload: {
  target_type: deliveryTarget.target_type,
  target_id: deliveryTarget.target_id,
  format: item.delivery_format || "markdown",
  title,
  body,
  blocks_or_html: body,
  thread_key: item.thread_key || "",
  dedupe_key: item.dedupe_key || `${item.workflow_id || "workflow"}:${deliveryTarget.target_type}:${deliveryTarget.target_id}`
} } }];
